    'olympic', 'olympics', 'football', 'basketball', 'baseball', 'soccer', 'tennis', 'hockey', 
    'golf', 'nfl', 'nba', 'mlb', 'nhl', 'fifa', 'uefa', 'wimbledon', 'world cup', 'super bowl', 
